import {
  apiDocs,
  apiMeta,
  blogCollection,
  changelogCollection,
  docs,
  integrationsCollection,
  legalCollection,
  meta,
} from "fumadocs-mdx:collections/server";
import { loader, multiple } from "fumadocs-core/source";
import { toFumadocsSource } from "fumadocs-mdx/runtime/server";
import { openapiSource } from "fumadocs-openapi/server";
import type { ApiPageProps } from "fumadocs-openapi/ui";
import { openapi } from "~/app/(app)/(content)/_lib/openapi";

// Docs source (general documentation)
const docsSource = loader({
  baseUrl: "/docs",
  source: toFumadocsSource(docs, meta),
});

// API source (API reference documentation)
// Combines manual MDX pages (getting-started, sdks-tools) with virtual OpenAPI endpoint pages
const apiSource = loader({
  baseUrl: "/docs/api-reference",
  source: multiple({
    mdx: toFumadocsSource(apiDocs, apiMeta),
    openapi: await openapiSource(openapi, {
      // Use operationId for flat URLs (no tag folders)
      // This generates /docs/api-reference/search, /docs/api-reference/contents, etc.
      groupBy: "none",
      per: "operation",
    }),
  }),
});

/**
 * Type helpers that properly infer the full collection entry type including DocData.
 *
 * These types provide access to runtime properties (body, toc, structuredData) that
 * are added by fumadocs-mdx v14 but lost in fumadocs-core v16 loader type inference.
 */

/** Full collection entry type for API MDX pages (includes body, toc, structuredData) */
export type ApiPageType = (typeof apiDocs)[number];

/**
 * Frontmatter type for general docs pages, derived directly from the collection type.
 * The collection entry IS the data object (no nested `.data`), matching how ApiPageType
 * is used: `page.data as DocsFrontmatter`.
 * Eliminates the need for a manually-maintained mirror interface.
 */
export type DocsFrontmatter = (typeof docs)[number];

/**
 * Type guard for fumadocs-openapi virtual pages.
 *
 * OpenAPI virtual pages expose `getAPIPageProps()` on their data object.
 * MDX pages expose `body`, `toc`, `structuredData` instead.
 *
 * Use this guard whenever you need to branch between OpenAPI and MDX pages
 * instead of repeating the inline duck-type check.
 */
interface OpenAPIPageData {
  description?: string;
  // ApiPageProps is exported from fumadocs-openapi/ui — no `any` needed
  getAPIPageProps: () => ApiPageProps;
  title?: string;
}

export function isOpenAPIPage(page: {
  data: unknown;
}): page is { data: OpenAPIPageData } {
  const data = page.data as Record<string, unknown>;
  return typeof data?.getAPIPageProps === "function";
}

// Export docs methods
export const { getPage, getPages, pageTree } = docsSource;

// Export API methods with different names
export const {
  getPage: getApiPage,
  getPages: getApiPages,
  pageTree: apiPageTree,
} = apiSource;

// --- Blog ---
const blogSource = loader({
  baseUrl: "/blog",
  source: toFumadocsSource(blogCollection, []),
});

export const getBlogPage = (slugs: string[]) => blogSource.getPage(slugs);
export const getBlogPages = () => blogSource.getPages();

// --- Changelog ---
const changelogSource = loader({
  baseUrl: "/changelog",
  source: toFumadocsSource(changelogCollection, []),
});

export const getChangelogPage = (slugs: string[]) =>
  changelogSource.getPage(slugs);
export const getChangelogPages = () => changelogSource.getPages();

// --- Legal ---
const legalSource = loader({
  baseUrl: "/legal",
  source: toFumadocsSource(legalCollection, []),
});

export const getLegalPage = (slugs: string[]) => legalSource.getPage(slugs);
export const getLegalPages = () => legalSource.getPages();

// --- Integrations ---
const integrationsSource = loader({
  baseUrl: "/integrations",
  source: toFumadocsSource(integrationsCollection, []),
});

export const getIntegrationPage = (slugs: string[]) =>
  integrationsSource.getPage(slugs);
export const getIntegrationPages = () => integrationsSource.getPages();

import { z } from "zod";

// Mirror of providerSlugSchema from @repo/app-providers/client. Inlined because
// fumadocs-mdx's build-time loader can't resolve the package's extensionless
// re-exports under Node ESM. Keep in sync with packages/app-providers/src/client/display.ts.
const providerSlugSchema = z.enum([
  "apollo",
  "github",
  "vercel",
  "linear",
  "sentry",
]);

const AuthorSchema = z.object({
  name: z.string().min(1),
  url: z.url(),
  twitterHandle: z.string().min(1),
  jobTitle: z.string().min(1).optional(),
});

const FaqItemSchema = z.object({
  question: z.string().min(10),
  answer: z.string().min(20),
});

const HowToStepSchema = z.object({
  name: z.string().min(1),
  text: z.string().min(20),
  url: z.url().optional(),
});

const BasePageSchema = z.object({
  title: z.string().min(1),
  description: z.string().min(50).max(160),
  keywords: z.array(z.string().min(1)).min(3).max(20),
  canonicalUrl: z.url(),
  ogTitle: z.string().min(1).max(70),
  ogDescription: z.string().min(50).max(160),
  noindex: z.boolean().default(false),
  nofollow: z.boolean().default(false),
});

const ContentPageSchema = BasePageSchema.extend({
  authors: z.array(AuthorSchema).min(1),
  publishedAt: z.iso.datetime(),
  updatedAt: z.iso.datetime(),
  faq: z.array(FaqItemSchema).min(1),
  featuredImage: z.string().startsWith("/images/").optional(),
});

export const BlogPostSchema = ContentPageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/blog/"))
    .optional(),
  category: z.enum([
    "engineering",
    "product",
    "company",
    "tutorial",
    "research",
  ]),
  readingTimeMinutes: z.number().int().min(1),
  featured: z.boolean().default(false),
  tldr: z.string().min(20).max(300),
  howToSteps: z.array(HowToStepSchema).min(2).optional(),
});

export const ChangelogEntrySchema = ContentPageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/changelog/"))
    .optional(),
  version: z.string().min(1),
  type: z.enum(["feature", "improvement", "fix", "breaking"]),
  tldr: z.string().min(20).max(300),
  improvements: z.array(z.string().min(1)).optional(),
});

export const LegalPageSchema = BasePageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/legal/"))
    .optional(),
  updatedAt: z.iso.datetime(),
  effectiveAt: z.iso.datetime(),
});

const IntegrationStatusSchema = z.enum(["live", "beta", "coming-soon"]);
const IntegrationCategorySchema = z.enum([
  "dev-tools",
  "monitoring",
  "comms",
  "data",
  "project-management",
]);

export const IntegrationPageSchema = BasePageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/integrations/"))
    .optional(),
  providerId: providerSlugSchema.optional(),
  tagline: z.string().min(10).max(120),
  category: IntegrationCategorySchema,
  featuredImage: z.string().startsWith("/images/").optional(),
  docsUrl: z.string().startsWith("/docs/").optional(),
  status: IntegrationStatusSchema.optional(),
  faq: z.array(FaqItemSchema).min(1).optional(),
  updatedAt: z.iso.datetime(),
});

export const DocsPageSchema = BasePageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/docs/"))
    .optional(),
  authors: z.array(AuthorSchema).min(1),
  publishedAt: z.iso.datetime(),
  updatedAt: z.iso.datetime(),
  proficiencyLevel: z
    .enum(["Beginner", "Intermediate", "Advanced", "Expert"])
    .optional(),
});

// Inferred TypeScript types
export type BlogPostData = z.infer<typeof BlogPostSchema>;
export type ChangelogEntryData = z.infer<typeof ChangelogEntrySchema>;
export type LegalPageData = z.infer<typeof LegalPageSchema>;
export type DocsPageData = z.infer<typeof DocsPageSchema>;
export type IntegrationPageData = z.infer<typeof IntegrationPageSchema>;
export type IntegrationCategory = IntegrationPageData["category"];
export type IntegrationStatus = IntegrationPageData["status"];

// Fields required by the SEO layer — satisfied structurally by BlogPostData,
// ChangelogEntryData, and DocsPageData. Derived from BlogPostData so schema
// renames propagate here automatically.
export type ContentSeoData = Pick<
  BlogPostData,
  | "authors"
  | "description"
  | "keywords"
  | "nofollow"
  | "noindex"
  | "ogDescription"
  | "ogTitle"
  | "publishedAt"
  | "title"
  | "updatedAt"
>;

// Derived from Zod — Zod is the sole source of truth for these unions
export type BlogCategory = BlogPostData["category"];
// → "engineering" | "product" | "company" | "tutorial" | "research"

export type ChangelogType = ChangelogEntryData["type"];
// → "feature" | "improvement" | "fix" | "breaking"

